+        let sidecar_path = PathBuf::from(sidecar_os);
+        if let Ok(meta) = std::fs::metadata(&sidecar_path)
+            && meta.len() > 0
+        {
+            return true;
+        }
+    }
+    false
+}
+
+#[allow(clippy::result_large_err)]
